#include<bits/stdc++.h>
using namespace std;
long long pos[500010],pos2[500010],c[500010],blk[500010],val[500010],l[500010],r[500010],pos1[500010];
long long blksiz;
struct node
{
    long long l,r,id;
    bool operator<(const node&b)const
    {
        if(blk[l]!=blk[b.l])
        {
            return l<b.l;
        }
        return r<b.r;
    }
}q[500010];
long long res,ans[500010];
void add(long long x)
{
    if(pos[c[x]]==0)
    {
        pos[c[x]]=x;
    }
    else
    {
        res=max(res,pos[c[x]]-x);
    }
}
void del(long long x)
{
    if(pos[c[x]]==x)
    {
        pos[c[x]]=0;
    }
}
int main()
{
    long long n,m;
    scanf("%lld",&n);
    blksiz=sqrt(n);
    for(long long i=1;(i-1)*blksiz+1<=n;i++)
    {
        l[i]=(i-1)*blksiz+1;
        r[i]=min(i*blksiz,n);
        for(long long j=l[i];j<=r[i];j++)
        {
            blk[j]=i;
        }
    }
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&c[i]);
        val[i]=c[i];
    }
    scanf("%lld",&m);
    sort(val+1,val+1+n);
    long long p=unique(val+1,val+1+n)-val-1;
    for(long long i=1;i<=n;i++)
    {
        c[i]=lower_bound(val+1,val+1+p,c[i])-val;
    }
    for(long long i=1;i<=m;i++)
    {
        scanf("%lld%lld",&q[i].l,&q[i].r);
        q[i].id=i;
    }
    sort(q+1,q+1+m);
    long long l=1,r=0,lst=-1;
    for(long long i=1;i<=m;i++)
    {
        if(blk[q[i].l]==blk[q[i].r])
        {
            for(long long j=q[i].l;j<=q[i].r;j++)
            {
                if(!pos1[c[j]])
                {
                    pos1[c[j]]=j;
                }
                else
                {
                    ans[q[i].id]=max(ans[q[i].id],j-pos1[c[j]]);
                }
            }
            for(long long j=q[i].l;j<=q[i].r;j++)
            {
                pos1[c[j]]=0;
            }
            continue;
        }
        if(blk[q[i].l]!=lst)
        {
            while(r>::r[blk[q[i].l]])
            {
                pos[c[r]]=pos2[c[r]]=0;
                r--;
            }
            while(l<::r[blk[q[i].l]]+1)
            {
                pos[c[l]]=pos2[c[l]]=0;
                l++;
            }
            res=0;
            lst=blk[q[i].l];
        }
        while(r<q[i].r)
        {
            r++;
            if(r>=l)
            {
                pos[c[r]]=r;
                if(!pos2[c[r]])
                {
                    pos2[c[r]]=r;
                }
                res=max(res,r-pos2[c[r]]);
            }
        }
        long long L=l;
        long long tmp=res;
        while(L>q[i].l)
        {
            L--;
            if(L<=r)
            {
                add(L);
            }
        }
        ans[q[i].id]=res;
        while(L<l)
        {
            if(L<=r)
            {
                del(L);
            }
            L++;
        }
        res=tmp;
    }
    for(long long i=1;i<=m;i++)
    {
        printf("%lld\n",ans[i]);
    }
    return 0;
}
